import path from "path";

import PDFDocument from "pdfkit";
import { NextResponse } from "next/server";
import * as XLSX from "xlsx";

import { resolvePlatformContext } from "@/lib/api/context";
import { requireSchoolModule } from "@/lib/module-governance";

type Row = Record<string, any>;

const money = (value: unknown) =>
  `₹${Number(value || 0).toLocaleString("en-IN", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`;

const text = (value: unknown, fallback = "-") => {
  const output = String(value ?? "").trim();
  return output || fallback;
};

const dateText = (value: unknown) => {
  if (!value) return "-";
  const date = new Date(String(value));
  return Number.isNaN(date.getTime())
    ? "-"
    : date.toLocaleDateString("en-IN", {
        day: "2-digit",
        month: "short",
        year: "numeric",
      });
};

function collectPdf(
  render: (doc: PDFKit.PDFDocument) => void
) {
  return new Promise<Buffer>((resolve, reject) => {
    const doc = new PDFDocument({
      size: "A4",
      margin: 32,
      bufferPages: true,
    });
    const chunks: Buffer[] = [];
    doc.on("data", (chunk) => chunks.push(Buffer.from(chunk)));
    doc.on("end", () => resolve(Buffer.concat(chunks)));
    doc.on("error", reject);
    render(doc);
    const range = doc.bufferedPageRange();
    for (let i = range.start; i < range.start + range.count; i += 1) {
      doc.switchToPage(i);
      doc.fontSize(8).fillColor("#6B7280").text(
        `Generated by TOTTECH ONE • Page ${i + 1} of ${range.count}`,
        32,
        805,
        { align: "center", width: 531 }
      );
    }
    doc.end();
  });
}

function visibleColumns(rows: Row[]) {
  const columns = [
    ["expense_date", "Expense Date"],
    ["category", "Category"],
    ["vendor_name", "Vendor"],
    ["school_name", "School"],
    ["academic_year", "Academic Year"],
    ["class_name", "Class"],
    ["section_name", "Section"],
    ["amount", "Amount"],
    ["payment_method", "Payment Mode"],
    ["reference_number", "Reference"],
    ["status", "Status"],
    ["created_by_name", "Created By"],
  ] as const;
  const keys = new Set(rows.flatMap((row) => Object.keys(row)));
  const selected = columns.filter(([key]) => keys.has(key));
  return selected.length ? selected : columns.slice(0, 8);
}

export async function GET(request: Request) {
  const guard = await requireSchoolModule("FINANCE");
  if (guard.response) return guard.response;

  const context = await resolvePlatformContext(request);
  if (!context) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const expenseUrl = new URL(request.url);
  expenseUrl.pathname = expenseUrl.pathname.replace(/\/export$/, "");
  expenseUrl.searchParams.delete("format");
  expenseUrl.searchParams.delete("type");

  const response = await fetch(expenseUrl.toString(), {
    headers: request.headers,
    cache: "no-store",
  });
  const payload = (await response.json()) as {
    context?: {
      selectedSchool?: Row | null;
      selectedAcademicYear?: Row | null;
      filters?: Row;
    };
    expenses?: Row[];
    summary?: Row;
    analytics?: Row;
  };

  const rows = payload.expenses || [];
  const summary = payload.summary || {};
  const selectedSchool = payload.context?.selectedSchool;
  const selectedAcademicYear = payload.context?.selectedAcademicYear;
  const filters = payload.context?.filters || {};
  const cols = visibleColumns(rows).slice(0, 8);

  const format = new URL(request.url).searchParams.get("format") === "xlsx" ? "xlsx" : "pdf";
  if (format === "xlsx") {
    const workbook = XLSX.utils.book_new();
    const detailRows = rows.map((row) => {
      const output: Record<string, unknown> = {};
      for (const [key, label] of cols) {
        output[label] = row[key] ?? "";
      }
      return output;
    });
    const summarySheet = XLSX.utils.json_to_sheet([
      {
        School: selectedSchool?.school_name || "All Schools",
        "Academic Year": selectedAcademicYear?.academic_year || "All Years",
        "Expense Count": summary.expenseCount || 0,
        "Total Expense": summary.totalExpense || 0,
        "Approved Expense": summary.approvedExpense || 0,
        "Pending Approval": summary.pendingApproval || 0,
        "Rejected Expense": summary.rejectedExpense || 0,
        "Paid Expense": summary.paidExpense || 0,
      },
    ]);
    const detailSheet = XLSX.utils.json_to_sheet(detailRows);
    XLSX.utils.book_append_sheet(workbook, summarySheet, "Summary");
    XLSX.utils.book_append_sheet(workbook, detailSheet, "Expenses");
    const workbookBuffer = XLSX.write(workbook, { type: "buffer", bookType: "xlsx" }) as Buffer;
    return new NextResponse(new Uint8Array(workbookBuffer), {
      headers: {
        "Content-Type":
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "Content-Disposition": `attachment; filename="school-expenses.xlsx"`,
      },
    });
  }

  const pdf = await collectPdf((doc) => {
    const logoUrl = selectedSchool?.logo_url ? String(selectedSchool.logo_url) : "";
    const logoPath = logoUrl.startsWith("/uploads")
      ? path.join(process.cwd(), "public", logoUrl)
      : null;
    if (logoPath) {
      try {
        doc.image(logoPath, 32, 24, { width: 42, height: 42 });
      } catch {
        // Fallback to text branding if image is unavailable.
      }
    }
    doc.fillColor("#071424").font("Helvetica-Bold").fontSize(18).text(
      selectedSchool?.school_name || "TOTTECH ONE",
      logoPath ? 82 : 32,
      28
    );
    doc.fillColor("#D4AF37").fontSize(10).text("School Expense Management Report", logoPath ? 82 : 32, 52);
    doc.fillColor("#6B7280").fontSize(8).text(
      `Academic Year: ${text(selectedAcademicYear?.academic_year, "All Years")}  •  Date Range: ${text(filters.from)} to ${text(filters.to)}  •  Generated: ${new Date().toLocaleString("en-IN")}`,
      logoPath ? 82 : 32,
      66,
      { width: 500 }
    );

    const summaryCards = [
      ["Count", summary.expenseCount || 0],
      ["Total", summary.totalExpense || 0],
      ["Approved", summary.approvedExpense || 0],
      ["Pending", summary.pendingApproval || 0],
      ["Rejected", summary.rejectedExpense || 0],
      ["Paid", summary.paidExpense || 0],
    ];
    summaryCards.forEach(([label, value], index) => {
      const x = 32 + (index % 3) * 170;
      const y = index < 3 ? 100 : 158;
      doc.roundedRect(x, y, 158, 50, 6).strokeColor("#D1D5DB").lineWidth(0.8).stroke();
      doc.fillColor("#6B7280").fontSize(8).font("Helvetica-Bold").text(String(label), x + 10, y + 10);
      doc.fillColor("#111827").fontSize(11).text(
        label === "Count" ? String(value) : money(value),
        x + 10,
        y + 26
      );
    });

    let y = 228;
    doc.fillColor("#F3F4F6").rect(32, y, 531, 24).fill();
    cols.forEach(([, label], index) => {
      const widths = [68, 68, 76, 70, 70, 56, 56, 60];
      doc.fillColor("#111827").fontSize(7).font("Helvetica-Bold").text(
        label,
        38 + widths.slice(0, index).reduce((a, b) => a + b, 0),
        y + 8,
        { width: widths[index] }
      );
    });
    y += 24;
    rows.slice(0, 120).forEach((row) => {
      if (y > 760) {
        doc.addPage();
        y = 40;
      }
      doc.strokeColor("#E5E7EB").moveTo(32, y).lineTo(563, y).stroke();
      cols.forEach(([key], index) => {
        const widths = [68, 68, 76, 70, 70, 56, 56, 60];
        const raw = row[key];
        const value = key.includes("amount")
          ? money(raw)
          : key.includes("date")
            ? dateText(raw)
            : text(raw);
        doc.fillColor("#111827").fontSize(7).font("Helvetica").text(
          value,
          38 + widths.slice(0, index).reduce((a, b) => a + b, 0),
          y + 8,
          { width: widths[index], height: 22 }
        );
      });
      y += 34;
    });
  });

  return new NextResponse(new Uint8Array(pdf), {
    headers: {
      "Content-Type": "application/pdf",
      "Content-Disposition": `attachment; filename="school-expenses.pdf"`,
    },
  });
}
